const DODESCA_0417_CORNERS=[["海上自衛隊撤退関連ニュース","06:00","06:00","news",["ニュース"],"6月までに結論を出す方針の海上自衛隊の撤退に関するニュースを伝えた。"],["天気予報","06:00","06:01","weather",["天気"],"名城公園からのリポートで、現在の気温（16度）、ひんやりとした空気、今日のポイントとして「暑さ落ち着き過ごしやすい」ことを伝えた。午前中は沿岸部で弱い雨の可能性があり、日差しは控えめだが長袖で快適に過ごせると予測した。"],["番組オープニングと季節の話題","06:01","06:02","opening",["天気","東海"],"午前6時の番組開始。武田と小型アナウンサー、コメンテーターの浅尾美和さんが挨拶。昨日は名古屋と岐阜で今年初の夏日を記録し、暑さを感じたとの話題から、今日の名古屋は21℃と平年並みで過ごしやすいが、昨日との気温差に注意するよう呼びかけた。"],["今朝のラインナップ","06:02","06:04","opening",["事件","国際"],"京都府南丹市の男児遺体事件、中東情勢の影響による医療用手袋の供給不足と国家備蓄放出のニュース、浅尾美和さんの「推しドラ」コーナー、中島健人のインタビュー、東山動植物園の赤カンガルー、幻の深海魚バラムツ釣りの企画「混乱飯」など、今朝の番組ラインナップを紹介した。"],["CM","06:04","06:06","cm",["東海","CM"],"番組提供スポンサーのCMとプレゼント企画の告知。JAバンクあいち、NDP名古屋トヨペット、明治LG21、サントリー、シナール、ワイモバイル、ミツカン、メナードなどのCMが流れた。"],["野球中継告知","06:06","06:07","sports",["中日ドラゴンズ"],"プロ野球「タイガース対ドラゴンズ」の試合がメーテレで生中継されることの告知。"],["交通情報","06:07","06:07","news",["ニュース"],"この地方の鉄道各社は平常通り運行しており、高速道路も順調な流れであることを伝えた。"],["サッカー日本代表コーチに中村俊輔氏","06:07","06:08","sports",["サッカー"],"日本サッカー協会が元日本代表の中村俊輔氏を日本代表コーチに任命したことを発表。森保監督が熱望し、中村氏も「世界で戦う日本代表選手たちと志を同じにし、チームが掲げる目標の達成に貢献できるよう努める」と意気込みを語った。"],["MLB大谷翔平・今永昇太の活躍","06:08","06:10","sports",["MLB"],"大谷翔平選手が2021年以来の投手専念で今シーズン2勝目を挙げ、ドジャース移籍後最多の10奪三振を記録。また、カブスの今永昇太投手も11奪三振で兄弟のフィリーズ相手に今シーズン初勝利を飾った。"],["MLB選手速報とドラゴンズ情報","06:10","06:11","sports",["中日ドラゴンズ","MLB"],"前日のMLBでの大谷翔平選手と今永昇太投手の活躍を速報で伝え、ジャッキー・ロビンソン・デーでの大谷選手の登場や、バッターとしての連続試合出塁記録について報じた。この後、浅尾美和さんの「推しドラ」コーナーへと続く。"],["CM","06:11","06:12","cm",["CM"],"「まるげん熟成醤油ラーメン肉そば」、「ダイレクト型自動車保険」、「肺炎球菌予防接種」、「本格炒め炒飯」などのCM。"],["CM","06:12","06:14","cm",["CM"],"SUV系プレミアムタイヤ「アレンザ」、「シャキうま塩野菜牛丼」、東京海上日動などのCM。世界ラリーやF1レーサー角田裕毅選手の対談、ラリージャパンの告知も含まれる。"],["浅尾美和の推しドラ！中日ドラゴンズ名場面集","06:14","06:17","sports",["中日ドラゴンズ"],"元プロビーチバレー選手の浅尾美和さんが、今シーズンのプロ野球中日ドラゴンズの試合から、自身が選んだ「もう一度見たい推しシーン」を紹介。大野雄大投手の連敗ストッパーとしてのピッチング、柳裕也投手の完封勝利とそれを支えた田中幹也選手の好守備、根尾昂投手のプロ初勝利と今季の活躍を振り返った。"],["中日ドラゴンズ：清水投手の実戦復帰と週末の試合","06:17","06:19","sports",["中日ドラゴンズ"],"腰の不調で調整していた清水達也投手が実戦復帰の可能性を示し、順調な回復ぶりを披露。今後、ファームでの試合で実戦復帰の可能性も伝えられた。週末の甲子園での阪神3連戦の先発予想（柳、大野、高橋宏斗）と放送予定も伝えられ、チームの巻き返しへの期待が語られた。"],["CM","06:19","06:20","cm",["CM"],"「楽楽販売」、ハーゲンダッツ、ダイハツ「ファンクロス」などのCM。"],["CM","06:20","06:21","cm",["CM"],"ダイハツ「ファンクロス」、Hotto Motto、第一生命グループ、喉の不快感を和らげる漢方薬などのCM。"],["天気予報","06:21","06:26","weather",["天気","東海"],"名城公園からビオラが咲く花壇の様子をリポートし、現在の気温（16度）、ひんやりとした空気、今日の予想最高気温（21度）を伝えた。午前中の弱い雨の可能性や雨雲の様子、各地の予報（名古屋・豊田21度、岡崎20度、岐阜21度、高山24度、津・大和瀬18度）、星なび、お帰り天気、そして週末は晴れ間が広がり気温も上がる週間予報を詳しく報じた。"],["ドデプレ！豪華商品プレゼント","06:26","06:26","sponsor",["ニュース"],"毎週豪華商品が当たる「ドデプレ」のコーナーで、今週はパナソニックの全自動コーヒーメーカー「ミルつき」を5名にプレゼントする告知を行った。"],["京都府南丹市 男児遺体遺棄事件","06:26","06:32","news",["事件"],"京都府南丹市の山林で11歳男児の遺体が見つかった事件で、逮捕された父親が殺害と遺棄を認める供述を新たにしていることが判明。父親の不可解な行動や、専門家による心理分析、そして現場からの最新状況を伝えた。"],["愛知県稲沢市 下水道処理施設で乳児遺体","06:32","06:33","news",["東海","事件"],"愛知県稲沢市の日光川上流浄化センターで性別不明の乳児の遺体が見つかり、警察が死体遺棄事件として捜査を開始したことを報じた。遺体は服を着ておらず、身長20センチくらいで、明らかな外傷はない。"],["イスラエルとレバノンが停戦合意","06:33","06:34","news",["ニュース"],"トランプ大統領が、攻撃が続いていたイスラエルとレバノンが10日間の停戦に合意したと発表。レバノン側は歓迎の声明を出したが、親イラン武装組織ヒズボラはイスラエルの敵対行為停止にかかるとの見解を示した。"],["中東情勢で医療用手袋供給不足、国家備蓄放出へ","06:34","06:35","news",["国際","政治"],"中東情勢の影響で石油由来の医療物資、特に医療用手袋の供給不足が懸念される中、高市総理大臣は国が備蓄している医療用手袋の在庫の一部（5億枚のうち5000万枚）を5月から放出する方針を表明した。"],["教師による児童盗撮事件、管理者に実刑判決","06:35","06:36","news",["東海","事件"],"教師がメンバーのSNSグループで児童の盗撮画像を共有した事件で、グループの管理者とされる名古屋市の元教師の男に懲役2年6ヶ月の実刑判決が言い渡された。被告は起訴内容を認めており、児童の心情を顧みない身勝手な動機に酌量の余地はないとされた。"],["日経平均株価が史上最高値を更新","06:36","06:37","news",["国際","経済"],"日経平均株価が市場最高値を更新し、取引を6万円目前の59,518円で終えた。前日の米国株式市場の株高やAI・半導体関連株の上昇、中東情勢終結への期待感が株価を支えた。"],["サントリーHD元会長 大麻成分含むサプリ密輸入で書類送検","06:37","06:37","news",["国際"],"サントリーホールディングスの新浪剛史元会長と知人女性が、大麻由来成分THCを違法な割合で含むサプリをアメリカから密輸入した疑いで書類送検された。新浪元会長は自宅から製品は見つからず、尿検査も陰性で、受け取っていないと主張している。"],["自転車の青切符制度悪用詐欺が愛知県で初確認","06:37","06:38","news",["東海"],"今月から始まった自転車の青切符制度を悪用した詐欺が愛知県内で初めて確認された。警察官を装った男が男子高校生から反則金を現金で要求したが、高校生が詐欺だと気づき被害を免れた。警察は現金要求があった場合は100番通報するよう呼び掛けている。"],["北海道根室市で大規模火災、自衛隊派遣へ","06:38","06:39","news",["ニュース"],"北海道根室市の草地で大規模な火災が発生し、約400ヘクタールが焼失。住民が消防に通報し、北海道は自衛隊に災害派遣を要請。付近の住民167世帯357人に対し避難指示が出された。"],["Travis Japan 新曲イベント開催、メンバー誕生日を祝福","06:39","06:41","news",["ニュース"],"Travis Japanが最新シングル「影にも日向にも」の発売記念イベントを開催し、900人のファンの前で新曲を披露。また、4月生まれの中村海人さんと松田元太さんの誕生日をサプライズで祝福した。最新シングルは発売初日で自己最高記録の25万枚を突破した。"],["timelesz佐藤勝利、アニメ映画で初主演＆初アフレコ","06:41","06:42","news",["ニュース"],"timeleszの佐藤勝利さんがアニメーション映画「君と花火と約束と」で初の主演とアフレコに挑戦。新潟の長岡まつり大花火大会を舞台にした青春ラブストーリーで、アフレコの難しさや作品への思い、そして新しい挑戦をする人々へのメッセージを語った。"],["中島健人、新CMでハプニングに遭遇","06:42","06:43","cm",["ニュース"],"中島健人さんが出演するミツカンの新しいCMが初公開され、インタビュー中に物が落ちるハプニングに遭遇。自身の「生き方を全肯定できるわけではない」という考えや、日常生活の思いがけないユニークな挑戦について語った。"],["白石麻衣がフラット35新CMに登場、忍者の隠れ身の術を披露","06:43","06:44","cm",["ニュース"],"白石麻衣さんがフラット35の新しいCMに出演し、忍者の隠れ身の術から登場するシーンがお気に入りだと語った。「忍者の気持ちになりました」と撮影の楽しさを振り返った。"],["東山動植物園の赤カンガルー：成長と袋の秘密","06:44","06:48","news",["ニュース"],"東山動植物園の筋肉質な赤カンガルーについて紹介。昨年から今年にかけて4頭の赤ちゃんが誕生し、袋から出たり入ったりしながら成長する様子を伝えた。カンガルーとコアラの袋の向きの違い、そして赤ちゃんカンガルーがお母さんの耳を引っ張って遊ぶという可愛らしい行動がクイズ形式で紹介された。"],["CM","06:48","06:50","cm",["CM"],"肩こり・腰痛薬「ゼノール」、家電量販店エディオン、ダイハツ「タフト」、ココス「濃厚ビーフシチューの包み焼きハンバーグ」、メガネ市場などのCM。"],["コーナー紹介","06:50","06:51","news",["ニュース"],"番組内の「春の誘い飯」や音楽ゲスト「CHEMISTRY」、「羊文学」などのコーナーを紹介した。"],["天気予報","06:51","06:59","weather",["天気","東海"],"東海地方の最新の天気情報をお伝えしました。"],["星座占い","06:59","07:00","news",["ニュース"],"各星座の今日の運勢とラッキーカラー、ラッキーアイテム、ラッキーフードなどを紹介した。リサさんがウルフィのサイコロで応援する星座を決定し、魚座を応援。"],["この後のラインナップ","07:00","07:00","opening",["グルメ","事件"],"午後の番組ラインナップを紹介。京都府南丹市の男児遺体事件、ドクターイエローの後継「ドクターS」、幻の深海魚バラムツ釣りに挑戦する「混乱飯」、そしてギルティグルメの特集が予告された。"],["京都府南丹市 男児遺体遺棄事件：父親の供述と不可解な行動","07:01","07:08","news",["事件"],"京都府南丹市の山林で発見された男児遺体事件について、逮捕された父親が殺害と遺棄を認める供述を新たにしていることが判明。父親が遺体を複数回移動させた可能性や、事件後の不可解な言動、過去の人物像が報じられた。また、犯罪心理学の専門家による行動分析や、現場からの最新中継も交え、事件の謎に迫った。"],["自転車の青切符制度悪用詐欺が愛知県で初確認","07:08","07:10","news",["東海"],"今月から始まった自転車の青切符制度を悪用した詐欺が愛知県内で初めて確認された。警察官を装った男が男子高校生から反則金を現金で要求したが、高校生が詐欺だと気づき被害を免れた。警察は現金要求があった場合は100番通報するよう呼び掛けている。"],["教師による児童盗撮事件、管理者に実刑判決","07:10","07:10","news",["東海","事件"],"教師がメンバーのSNSグループで児童の盗撮画像を共有した事件で、グループの管理者とされる名古屋市の元教師の男に懲役2年6ヶ月の実刑判決が言い渡された。被告は起訴内容を認めており、児童の心情を顧みない身勝手な動機に酌量の余地はないとされた。"],["北海道根室市で大規模火災、自衛隊派遣へ","07:10","07:12","news",["ニュース"],"北海道根室市の草地で大規模な火災が発生し、約400ヘクタールが焼失。住民が消防に通報し、北海道は自衛隊に災害派遣を要請。付近の住民167世帯357人に対し避難指示が出された。"],["ポーランドでイノシシ対策に人型ロボット","07:12","07:13","news",["ニュース"],"ポーランドのワルシャワで、街に現れる野生のイノシシ対策として人型ロボットが使われていることが紹介された。ロボットがイノシシを追い払う映像とともに、この対策に対する賛否両論が報じられた。"],["ドクターイエロー後継「ドクターS」デビュー","07:13","07:16","news",["東海"],"「見ると幸せになれる」と言われる新幹線ドクターイエローの後継車両として、JR東海が「ドクターS」を発表。最新型車両N700Sに検査機能を搭載し、営業運転しながら線路や架線の点検を行う。2024年10月から営業、2025年1月から検査車両として運行開始予定。"],["日経平均株価が史上最高値を更新","07:16","07:17","news",["国際","経済"],"日経平均株価が市場最高値を更新し、取引を6万円目前の59,518円で終えた。前日の米国株式市場の株高やAI・半導体関連株の上昇、中東情勢終結への期待感が株価を支えた。"],["愛知県稲沢市 下水道処理施設で乳児遺体","07:17","07:18","news",["東海","事件"],"愛知県稲沢市の日光川上流浄化センターで性別不明の乳児の遺体が見つかり、警察が死体遺棄事件として捜査を開始したことを報じた。遺体は服を着ておらず、身長20センチくらいで、明らかな外傷はない。"],["埼玉・秩父市の半導体工場で爆発、作業員4人重軽傷","07:18","07:19","news",["ニュース"],"埼玉県秩父市の半導体製造工場で、配管清掃中に爆発が発生し、作業員4人が重軽傷を負った。警察が詳しい原因を調べている。"],["幻の深海魚「バラムツ」釣りに挑戦！","07:19","07:31","news",["東海","グルメ"],"三重県熊野灘で、幻の深海魚「バラムツ」釣りに武田アナウンサーが挑戦。バラムツは食用油を多く含み流通が禁止されているが、漁師の間では絶品とされる。釣りの難しさに加え、アシスタントディレクターが実食した刺身の味もレポートされた。"],["【速報】フィギュアスケート「りくりゅう」ペア引退を発表","07:31","07:32","sports",["ニュース"],"フィギュアスケートペアで日本勢史上初の金メダルを獲得した三浦璃来選手と木原龍一選手の「りくりゅう」ペアが、今シーズン限りでの引退を発表した。ミラノ・コルティナオリンピックでの活躍を振り返りつつ、SNSで「これからもペアを日本の皆様にもっと知っていただけるよう、新しいことに2人で挑戦していく」とコメントしていることも伝えた。"],["天気予報","07:33","07:38","weather",["天気","東海"],"名城公園からのネモフィラ満開のリポートに続き、名古屋のトコトン詳しい天気として、朝の弱い雨の可能性、日中の日差しと最高気温（21度）、昨日との寒暖差への注意を呼びかけた。東海3県各地の現在の空の様子、雨雲レーダー、予想天気図、各地域の詳細予報、お帰り天気、週末の行楽日和と夏日復活の週間予報、花粉の週間予測まで、詳細な天気情報を伝えた。"],["ドデプレ！豪華商品プレゼント","07:38","07:38","sponsor",["ニュース"],"毎週豪華商品が当たる「ドデプレ」のコーナーで、今週はパナソニックの全自動コーヒーメーカー「ミルつき」を5名にプレゼントする告知を行った。"],["ギルティーグルメ特集直前！ウルフィの見えるかな？","07:39","07:39","feature",["グルメ"],"「後ろめたくてもやめられない」ギルティーグルメの特集告知と共に、画面を横切るものを当てるミニクイズ「ウルフィの見えるかな？」が行われた。"],["CM","07:39","07:42","cm",["CM"],"明治安田、オープンハウス、MySignal、オーマイプレミアム、ムヒベタS、日本テクノ、S&B、楽楽勤怠、特茶、WiMAX、ローソン「でからあげクン」、THRIVE、クランキー、イエローハットなどのCM。"],["ウルフィの見えるかな？クイズ結果発表","07:42","07:42","news",["ニュース"],"「ウルフィの見えるかな？」クイズの正解が発表された。"],["今日のイチオシ！やめられない「ギルティグルメ」特集","07:42","07:47","feature",["グルメ"],"高カロリー・高脂質・濃い味が特徴の「ギルティグルメ」を特集。サントリーの炭酸飲料「NOPE」の驚異的な売上、ラーメン二郎インスパイア系の「オムジロウ」、噛んで食べる「ナッツボン 塩バター味」など、SNSで話題のグルメを紹介した。"],["CM・番組宣伝","07:47","07:48","cm",["CM"],"ドラマ「無垢なる証人」の番組宣伝、「流水麺」、日本テクノ「エコテナント」、エスビー「予約でいっぱいの店のパスタソース」などのCM。"],["CM","07:48","07:50","cm",["CM"],"「特茶」、WiMAX、ローソン「でからあげクン」新商品、スライブのマッサージチェアなどのCM。"],["ヒコロヒー、齊藤京子、ROIROM本田ひろむが看護師転職サービスCM出演","07:50","07:51","cm",["ニュース"],"看護師専門の転職サービスのCMに、ヒコロヒーさん、齊藤京子さん、そして来月メジャーデビューするアイドルユニットROIROMの本田ひろむさんが出演。本田さんは新人看護師役を熱演し、共演者との仕事に対する考え方も語られた。"],["安城市の喫茶店で「ハチミツベーコンチーズトースト」モーニング","07:51","07:55","feature",["東海"],"愛知県安城市の創業60年以上続く喫茶店で、春夏限定の「ハチミツベーコンチーズトーストモーニング」を紹介。分厚いトーストにチーズとベーコン、そしてたっぷりのハチミツをかけた、甘じょっぱい味わいが特徴。サラダとヨーグルトもセット。"],["【速報】フィギュアスケート「りくりゅう」ペア引退を発表","07:55","07:56","sports",["ニュース"],"フィギュアスケートペアで日本勢史上初の金メダルを獲得した三浦璃来選手と木原龍一選手の「りくりゅう」ペアが、今シーズン限りでの引退を発表した。ミラノ・コルティナオリンピックでの活躍を振り返りつつ、SNSで「これからもペアを日本の皆様にもっと知っていただけるよう、新しいことに2人で挑戦していく」とコメントしていることも伝えた。"],["CM・番組宣伝","07:56","07:58","cm",["CM"],"羽鳥慎一モーニングショーの番組宣伝、レゴランド、ポカリスエット、大人の自動車保険、フルグラ、ヤマダホームズ、再生柔軟剤リウェア、肺炎球菌予防接種などのCM。"],["交通情報と不発弾処理に伴う交通規制","07:58","07:59","news",["東海"],"東名阪道の集中工事による渋滞情報と、名古屋市東区で見つかった不発弾処理に伴う地下鉄東山線・桜通線の一部区間運休、市バスの迂回運転について伝えた。"],["天気予報","07:59","08:01","weather",["天気","東海"],"名城公園からのネモフィラ満開のリポートに続き、名古屋のトコトン詳しい天気として、朝の弱い雨の可能性、日中の日差しと最高気温（21度）、昨日との寒暖差への注意を呼びかけた。東海3県各地の現在の空の様子、雨雲レーダー、予想天気図、各地域の詳細予報、お帰り天気、週末の行楽日和と夏日復活の週間予報、花粉の週間予測まで、詳細な天気情報を伝えた。また、夕方のドデスカプラス特集「町イチ」で津島市の天ぷらうどんが紹介されることや、天皇川公園藤まつりからの松崎さんの生中継が予告された。"]];

function pickFromPool(poolName, seed){
  const pool = POOLS[poolName] || POOLS.cm;
  const idx = seed % pool.length;
  return pool[idx];
}

function buildDaily(template, date){
  const seedBase = date.split("-").reduce((a,b)=>a+parseInt(b),0);
  const out = {};
  let counter = 0;
  for(const stId of Object.keys(template)){
    out[stId] = template[stId].map(([pName,pS,pE,corners])=>{
      const newCorners = corners.map(([title,cs,ce,seg,pool])=>{
        counter++;
        const seed = seedBase * 31 + counter * 17;
        const [poolTitle, poolSummary, poolTagsStr] = pickFromPool(pool, seed);
        const tags = poolTagsStr.split(",");
        // poolTitleを活かしつつ、もとのコーナータイトル枠も併記
        const finalTitle = (pool==="cm"||pool==="sponsor"||pool==="kids"||pool==="opening"||pool==="ending") ? title : poolTitle;
        return [finalTitle, cs, ce, seg, tags, poolSummary];
      });
      return [pName, pS, pE, newCorners];
    });
  }
  return out;
}

function getDailyMorn(date){
  const result=buildDaily(MORN_TPL,date);
  if(date==="2026-04-17"){
    const nbnPre=result.NBN.slice(0,2);
    const morning=result.NBN[3];
    result.NBN=[...nbnPre,["ドデスカ!","06:00","08:00",DODESCA_0417_CORNERS],morning];
  }
  return result;
}
function getDailyEve(date){ return buildDaily(EVE_TPL, date); }


function sRand(s){let x=s;return()=>{x=(x*16807)%2147483647;return(x-1)/2147483646;};}


function WeatherBadge({ weather }) {
  if (!weather) return null;
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 5, padding: "3px 10px", borderRadius: 6, background: "#F0F9FF", border: "1px solid #BAE6FD" }}>
      <span style={{ fontSize: 16 }}>{weather.icon}</span>
      <span style={{ fontSize: 11, color: "#0369A1", fontFamily: "monospace", fontWeight: 600, whiteSpace: "nowrap" }}>
        {weather.max.toFixed(1)}℃ | {weather.min.toFixed(1)}℃
      </span>
    </div>
  );
}

// ============================================================
// 実データ (名古屋地区世帯視聴率, 1分刻み)
// 列順: [NBN, THK, CTV, CBC, NHK, NHKE, TVA]
// 該当する date|slot に実データがあればそれを使い、なければシード乱数で生成
// ============================================================
const REAL_RATINGS_COLS = ["NBN","THK","CTV","CBC","NHK","NHKE","TVA"];
const REAL_RATINGS = REAL_RATINGS_IMPORT;

function genRatings(date,slot){
  const sm=slot==="morning"?330:960, em=slot==="morning"?509:1169;
  const realKey=`${date}|${slot}`;
  // ----- 実データがあればそれを使用 -----
  if(REAL_RATINGS[realKey]){
    const raw=REAL_RATINGS[realKey];
    const data=[];
    for(let i=0;i<raw.length;i++){
      const m=sm+i;
      const row=raw[i];
      const e={time:m2t(m),minute:m};
      REAL_RATINGS_COLS.forEach((sid,j)=>{e[sid]=row[j];});
      data.push(e);
    }
    return data;
  }
  // ----- 実データがない日は実データ2日分の平均プロファイルを基にシード乱数で揺らぎを加える -----
  const profile=slot==="morning"?MORN_PROFILE:EVE_PROFILE;
  const seed=date.split("-").reduce((a,b)=>a+parseInt(b),0)*31+(slot==="morning"?7:1777);
  const r=sRand(seed);
  // その日「強い局」「弱い局」を1つずつランダムに選び、軽くブースト/減衰
  const stIds=ST.map(s=>s.id);
  const strongSt=stIds[Math.floor(r()*stIds.length)];
  const weakSt=stIds[Math.floor(r()*stIds.length)];
  // 各局の日替わり係数（0.85〜1.15）
  const dayMult={};
  stIds.forEach(sid=>{dayMult[sid]=0.85+r()*0.30;});
  dayMult[strongSt]*=1.10;
  dayMult[weakSt]*=0.92;
  const data=[];
  for(let m=sm;m<=em;m++){
    const idx=m-sm;
    const baseRow=profile[Math.min(idx,profile.length-1)]; // [NBN,THK,CTV,CBC,NHK,NHKE,TVA]
    const e={time:m2t(m),minute:m};
    REAL_RATINGS_COLS.forEach((sid,j)=>{
      const noise=1+(r()-0.5)*0.30; // 分単位の揺らぎ ±15%（ギザギザ感）
      e[sid]=Math.max(0.05,baseRow[j]*dayMult[sid]*noise);
    });
    data.push(e);
  }
  // 軽くスムージング（隣接3点の重み付け平均）
  // ギザギザ感を残すため軽いスムージング1回のみ
  for(let i=1;i<data.length-1;i++)stIds.forEach(sid=>{
    data[i][sid]=(data[i-1][sid]+data[i][sid]*2+data[i+1][sid])/4;
  });
  return data;
}

// 実データ2日分の平均プロファイル: 各分の [NBN,THK,CTV,CBC,NHK,NHKE,TVA]
// 実データがない日のベース値として使用される
const MORN_PROFILE = PROFILES_IMPORT.mornProfile;
const EVE_PROFILE = PROFILES_IMPORT.eveProfile;


function getProg(slot,stId,min,date){
  const tpl=slot==="morning"?(date?getDailyMorn(date):buildDaily(MORN_TPL,"2026-04-01")):(date?getDailyEve(date):buildDaily(EVE_TPL,"2026-04-01"));
  const progs=tpl[stId]||[];
  for(const[n,s,e,corners] of progs){
    if(min>=t2m(s)&&min<t2m(e)){
      let c=null;
      for(const cn of corners){
        const[title,cs,ce,segment,tags,summary]=cn;
        if(min>=t2m(cs)&&min<t2m(ce)){c={title,startMin:cs,endMin:ce,segment,tags,summary};break;}
      }
      return {prog:{name:n,start:s,end:e,corners},corner:c};
    }
  }
  return{prog:null,corner:null};
}

function getAllCorners(slot,stId,date){
  const tpl=slot==="morning"?(date?getDailyMorn(date):buildDaily(MORN_TPL,"2026-04-01")):(date?getDailyEve(date):buildDaily(EVE_TPL,"2026-04-01"));
  const progs=tpl[stId]||[];
  const out=[];
  for(const[n,s,e,corners] of progs){
    for(const cn of corners){
      const[title,cs,ce,segment,tags,summary]=cn;
      out.push({title,startMin:cs,endMin:ce,segment,tags,summary,progName:n});
    }
  }
  return out;
}

function SegmentBand({slot,stId,startMin,endMin,height=14,onHover,date}){
  const corners=useMemo(()=>getAllCorners(slot,stId,date),[slot,stId,date]);
  const total=endMin-startMin;
  return <div style={{position:"relative",display:"flex",height,background:"#F3F4F6",borderRadius:3,overflow:"hidden",border:"1px solid #E5E7EB"}}>
    {corners.map((c,i)=>{
      const cS=t2m(c.startMin),cE=t2m(c.endMin);
      const left=((Math.max(cS,startMin)-startMin)/total)*100;
      const width=((Math.min(cE,endMin)-Math.max(cS,startMin))/total)*100;
      if(width<=0)return null;
      const sg=SEG[c.segment]||SEG.other;
      return <div key={i} title={`${c.title} (${c.startMin}-${c.endMin})`}
        onMouseEnter={()=>onHover&&onHover(c)} onMouseLeave={()=>onHover&&onHover(null)}
        style={{position:"absolute",left:`${left}%`,width:`${width}%`,height:"100%",background:sg.c,borderRight:"1px solid rgba(255,255,255,0.4)",cursor:"pointer"}}/>;
    })}
  </div>;
}

function Chart({data,sel,onClick,selMin,hl,metric,onPan}){
  const ref=useRef(null),cRef=useRef(null);
  const[hv,setHv]=useState(null);
  const[d,setD]=useState({w:900,h:340});
  const[dragging,setDragging]=useState(false);
  const dragX=useRef(0);
  const hasDragged=useRef(false);
  useEffect(()=>{const o=new ResizeObserver(es=>{for(const e of es)setD({w:e.contentRect.width,h:Math.min(400,Math.max(280,e.contentRect.height))});});if(cRef.current)o.observe(cRef.current);return()=>o.disconnect();},[]);
  const p={t:28,r:16,b:38,l:34},cW=d.w-p.l-p.r,cH=d.h-p.t-p.b;
  const mpp=data.length>1?(data.length-1)/cW:1;
  const mx=useMemo(()=>{if(metric==="share")return 60;let x=0;data.forEach(dt=>sel.forEach(s=>{if(dt[s]>x)x=dt[s];}));return Math.ceil(x+1);},[data,sel,metric]);
  const xS=useCallback(i=>p.l+(i/(data.length-1))*cW,[data.length,cW]);
  const yS=useCallback(v=>p.t+cH-(v/mx)*cH,[cH,mx]);
  const gi=useCallback(cx=>{const rc=ref.current?.getBoundingClientRect();if(!rc)return-1;return Math.max(0,Math.min(data.length-1,Math.round(((cx-rc.left-p.l)/cW)*(data.length-1))));},[cW,data.length]);
  const tL=useMemo(()=>{const l=[];const st=data.length>100?10:5;for(let i=0;i<data.length;i+=st)l.push({i,lb:data[i].time});return l;},[data]);
  const yT=useMemo(()=>{const t=[];const st=metric==="share"?10:2;for(let i=0;i<=mx;i+=st)t.push(i);return t;},[mx,metric]);
  const si=data.findIndex(dt=>dt.minute===selMin);
  let hs=-1,he=-1;if(hl){hs=data.findIndex(dt=>dt.minute===hl.start);he=data.findIndex(dt=>dt.minute===hl.end);}
  const hc=(ST.find(s=>s.id===hl?.stationId)||{c:"#888"}).c;
  return <div ref={cRef} style={{width:"100%",height:"100%",minHeight:280}}>
    <svg ref={ref} width={d.w} height={d.h} style={{cursor:onPan?(dragging?"grabbing":"grab"):"crosshair",display:"block",userSelect:"none"}}
      onClick={e=>{if(hasDragged.current){hasDragged.current=false;return;}const i=gi(e.clientX);if(i>=0&&data[i])onClick(data[i].minute);}}
      onMouseDown={e=>{if(!onPan||e.button!==0)return;setDragging(true);dragX.current=e.clientX;hasDragged.current=false;e.preventDefault();}}
      onMouseMove={e=>{if(dragging&&onPan){const dx=e.clientX-dragX.current;if(Math.abs(dx)>3)hasDragged.current=true;dragX.current=e.clientX;onPan(-dx*mpp);}const i=gi(e.clientX);if(i>=0)setHv(i);}}
      onMouseUp={()=>setDragging(false)}
      onMouseLeave={()=>{setDragging(false);setHv(null);}}>
      <rect x={0} y={0} width={d.w} height={d.h} fill="#FAFBFC" rx={8}/>
      {yT.map(v=><g key={v}><line x1={p.l} x2={d.w-p.r} y1={yS(v)} y2={yS(v)} stroke="#E5E7EB" strokeDasharray="2,4"/><text x={p.l-6} y={yS(v)+4} fill="#9CA3AF" fontSize="10" textAnchor="end" fontFamily="monospace">{v}%</text></g>)}
      {tL.map(({i,lb})=><text key={i} x={xS(i)} y={d.h-8} fill="#9CA3AF" fontSize="9.5" textAnchor="middle" fontFamily="monospace">{lb}</text>)}
      {hs>=0&&he>=0&&<rect x={xS(hs)} y={p.t} width={Math.max(xS(he)-xS(hs),2)} height={cH} fill={hc} opacity={0.07} rx={2}/>}
      {hs>=0&&<line x1={xS(hs)} x2={xS(hs)} y1={p.t} y2={p.t+cH} stroke={hc} strokeWidth={1.5} opacity={0.4} strokeDasharray="4,3"/>}
      {he>=0&&<line x1={xS(he)} x2={xS(he)} y1={p.t} y2={p.t+cH} stroke={hc} strokeWidth={1.5} opacity={0.4} strokeDasharray="4,3"/>}
      {sel.map(sid=>{const st=ST.find(s=>s.id===sid);const iH=hl?.stationId===sid;const hH=!!hl;return <path key={sid} d={data.map((dt,i)=>`${i===0?"M":"L"}${xS(i)},${yS(dt[sid])}`).join(" ")} fill="none" stroke={st.c} strokeWidth={hH?(iH?1:0.8):1.5} opacity={hH?(iH?0.3:0.15):0.85}/>;})}
      {hl&&hs>=0&&he>=0&&sel.includes(hl.stationId)&&(()=>{const sid=hl.stationId;const st=ST.find(s=>s.id===sid);const s0=Math.max(hs,0),s1=Math.min(he,data.length-1);const sg=data.slice(s0,s1+1).map((dt,i)=>`${i===0?"M":"L"}${xS(s0+i)},${yS(dt[sid])}`).join(" ");return <><path d={sg} fill="none" stroke={st.c} strokeWidth={3.5} opacity={1} strokeLinecap="round"/><circle cx={xS(s0)} cy={yS(data[s0][sid])} r={4} fill={st.c} stroke="#fff" strokeWidth={2}/><circle cx={xS(s1)} cy={yS(data[s1][sid])} r={4} fill={st.c} stroke="#fff" strokeWidth={2}/></>;})()}
      {si>=0&&<line x1={xS(si)} x2={xS(si)} y1={p.t} y2={p.t+cH} stroke="#6B7280" strokeWidth={1} strokeDasharray="4,4"/>}
      {hv!==null&&data[hv]&&<>
        <line x1={xS(hv)} x2={xS(hv)} y1={p.t} y2={p.t+cH} stroke="#D1D5DB" strokeWidth={1}/>
        {sel.map(sid=>{const st=ST.find(s=>s.id===sid);return <circle key={sid} cx={xS(hv)} cy={yS(data[hv][sid])} r={3} fill={st.c} stroke="#fff" strokeWidth={1.5}/>;})}
        <g>
          <rect x={Math.min(xS(hv)+10,d.w-165)} y={p.t} width={150} height={18+sel.length*16} rx={5} fill="rgba(255,255,255,0.97)" stroke="#E5E7EB"/>
          <text x={Math.min(xS(hv)+18,d.w-157)} y={p.t+13} fill="#374151" fontSize="10.5" fontFamily="monospace" fontWeight="600">{data[hv].time}</text>
          {sel.map((sid,i)=>{const st=ST.find(s=>s.id===sid);return <g key={sid}><circle cx={Math.min(xS(hv)+20,d.w-155)} cy={p.t+28+i*16} r={3.5} fill={st.c}/><text x={Math.min(xS(hv)+28,d.w-147)} y={p.t+32+i*16} fill="#374151" fontSize="10" fontFamily="monospace">{st.id} {data[hv][sid].toFixed(metric==="share"?1:2)}%</text></g>;})}
        </g>
      </>}
    </svg>
  </div>;
}

function Toggle({sel,onT}){
  return <div style={{display:"flex",flexWrap:"wrap",gap:5,alignItems:"center"}}>
    <span style={{color:"#9CA3AF",fontSize:10,fontFamily:"monospace",marginRight:2}}>表示設定</span>
    {ST.map(s=><button key={s.id} onClick={()=>onT(s.id)} style={{display:"flex",alignItems:"center",gap:4,padding:"3px 9px",borderRadius:16,border:`1.5px solid ${sel.includes(s.id)?s.c:"#E5E7EB"}`,background:sel.includes(s.id)?`${s.c}0D`:"transparent",color:sel.includes(s.id)?s.c:"#9CA3AF",cursor:"pointer",fontSize:11,fontWeight:600,fontFamily:"monospace"}}>
      <span style={{width:7,height:7,borderRadius:"50%",background:sel.includes(s.id)?s.c:"#D1D5DB"}}/>{s.id}
    </button>)}
  </div>;
}

function SegmentLegend(){
  return <div style={{display:"flex",flexWrap:"wrap",gap:10,alignItems:"center",padding:"8px 12px",background:"#FAFBFC",borderRadius:6,border:"1px solid #F3F4F6"}}>
    <span style={{color:"#6B7280",fontSize:10,fontFamily:"monospace",fontWeight:600,letterSpacing:"0.05em"}}>セグメント</span>
    {SEG_ORDER.map(k=><div key={k} style={{display:"flex",alignItems:"center",gap:4}}>
      <span style={{width:10,height:10,background:SEG[k].c,borderRadius:2}}/>
      <span style={{fontSize:10.5,color:"#4B5563"}}>{SEG[k].lb}</span>
    </div>)}
  </div>;
}

function SegmentBands({slot,sel,selMin,onClickMinute,date,customStart,customEnd}){
  const[hoverC,setHoverC]=useState(null);
  const startMin=customStart!==undefined?customStart:(slot==="morning"?330:960), endMin=customEnd!==undefined?customEnd:(slot==="morning"?510:1170);
  const total=endMin-startMin;
  const nowLeft=selMin!=null?((selMin-startMin)/total)*100:-1;
  const containerRef=useRef(null);
  const click=(e,stId)=>{
    const rect=e.currentTarget.getBoundingClientRect();
    const x=e.clientX-rect.left;
    const trackW=rect.width; // marginRight:16は親のflexで処理済みなのでそのまま
    const min=startMin+Math.round((x/trackW)*total);
    onClickMinute(Math.max(startMin,Math.min(endMin,min)));
  };
  return <div ref={containerRef} style={{background:"#fff",border:"1px solid #F3F4F6",borderRadius:8,padding:"10px 0"}}>
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8,padding:"0 16px 0 34px"}}>
      <span style={{color:"#111827",fontSize:12,fontWeight:700}}>セグメント構成タイムライン</span>
      {hoverC&&<span style={{fontSize:10.5,color:"#6B7280"}}>{hoverC.progName} ・ <b style={{color:"#111827"}}>{hoverC.title}</b> ({hoverC.startMin}-{hoverC.endMin}) <span style={{color:SEG[hoverC.segment]?.c,fontWeight:600,marginLeft:4}}>{SEG[hoverC.segment]?.lb}</span></span>}
    </div>
    <div style={{position:"relative"}}>
      {sel.map(sid=>{const st=ST.find(s=>s.id===sid);return <div key={sid} style={{display:"flex",alignItems:"center",marginBottom:4}}>
        <span style={{width:34,fontSize:9.5,fontWeight:700,color:st.c,fontFamily:"monospace",textAlign:"right",paddingRight:4,flexShrink:0}}>{sid}</span>
        <div style={{flex:1,marginRight:16}} onClick={e=>click(e,sid)}>
          <SegmentBand slot={slot} stId={sid} startMin={startMin} endMin={endMin} onHover={setHoverC} date={date}/>
        </div>
      </div>;})}
      {nowLeft>=0&&<div style={{position:"absolute",top:0,bottom:0,left:`calc(34px + (100% - 34px - 16px) * ${nowLeft/100})`,width:1,background:"rgba(220,38,38,0.6)",pointerEvents:"none"}}/>}
    </div>
  </div>;
}

function TimetableView({slot,sel,allR,allS,metric,date,onCornerClick}){
  const startMin=slot==="morning"?330:960, endMin=slot==="morning"?510:1170;
  const fmt=v=>v!=null?(metric==="share"?v.toFixed(1):v.toFixed(2))+"%":"—";
  const getVal=(src,sid,min)=>{const e=src?.find(d=>d.minute===min);return e?e[sid]:null;};
  const colWidth=220;
  const pxPerMin=22;
  const totalMin=endMin-startMin;
  const totalH=totalMin*pxPerMin;
  const timeMarks=[];for(let m=startMin;m<=endMin;m+=10)timeMarks.push(m);
  return <div style={{background:"#fff",border:"1px solid #E5E7EB",borderRadius:8,overflow:"auto",maxHeight:"calc(100vh - 220px)"}}>
    <div style={{display:"flex",minWidth:60+sel.length*colWidth}}>
      <div style={{width:60,flexShrink:0,position:"sticky",left:0,background:"#F9FAFB",borderRight:"1px solid #E5E7EB",zIndex:2}}>
        <div style={{height:42,borderBottom:"1px solid #E5E7EB",display:"flex",alignItems:"center",justifyContent:"center",fontSize:10,color:"#6B7280",fontWeight:700,fontFamily:"monospace",position:"sticky",top:0,background:"#F3F4F6",zIndex:3}}>TIME</div>
        <div style={{position:"relative",height:totalH}}>
          {timeMarks.map(m=><div key={m} style={{position:"absolute",top:(m-startMin)*pxPerMin,left:0,right:0,fontSize:9.5,color:"#9CA3AF",fontFamily:"monospace",paddingLeft:6,borderTop:"1px dashed #E5E7EB",height:pxPerMin*10,display:"flex",alignItems:"flex-start",paddingTop:2}}>{m2t(m)}</div>)}
        </div>
      </div>
      {sel.map(sid=>{
        const st=ST.find(s=>s.id===sid);
        const tpl=slot==="morning"?getDailyMorn(date):getDailyEve(date);
        const progs=tpl[sid]||[];
        const corners=[];
        for(const[n,s,e,cs] of progs){for(const c of cs)corners.push({progName:n,title:c[0],startMin:c[1],endMin:c[2],segment:c[3],tags:c[4],summary:c[5]});}
        return <div key={sid} style={{width:colWidth,flexShrink:0,borderRight:"1px solid #E5E7EB",position:"relative"}}>
          <div style={{height:42,borderBottom:"1px solid #E5E7EB",display:"flex",alignItems:"center",justifyContent:"center",gap:6,background:"#F3F4F6",position:"sticky",top:0,zIndex:3}}>
            <span style={{background:st.c,color:"#fff",fontSize:9.5,fontWeight:800,padding:"2px 6px",borderRadius:3,fontFamily:"monospace"}}>{sid}</span>
            <span style={{fontSize:10.5,color:"#374151",fontWeight:600}}>{st.nm}</span>
          </div>
          <div style={{position:"relative",height:totalH}}>
            {timeMarks.map(m=><div key={m} style={{position:"absolute",top:(m-startMin)*pxPerMin,left:0,right:0,borderTop:"1px dashed #F3F4F6",height:0}}/>)}
            {corners.map((c,i)=>{
              const cS=Math.max(t2m(c.startMin),startMin),cE=Math.min(t2m(c.endMin),endMin);
              if(cE<=cS)return null;
              const top=(cS-startMin)*pxPerMin;
              const height=(cE-cS)*pxPerMin;
              const sg=SEG[c.segment]||SEG.other;
              const src=metric==="share"?allS:allR;
              const iV=getVal(src,sid,t2m(c.startMin));
              const oV=getVal(src,sid,Math.min(t2m(c.endMin),src[src.length-1].minute));
              const df=(iV!=null&&oV!=null)?oV-iV:null;
              const isCM=c.segment==="cm";
              const compact=height<40;
              return <div key={i} onClick={()=>onCornerClick&&onCornerClick({...c,stId:sid,date,slot})}
                style={{position:"absolute",top,left:4,right:4,height:height-2,background:isCM?"#FAFAFA":"#fff",border:`1px solid #E5E7EB`,borderLeft:`3px solid ${sg.c}`,borderRadius:4,padding:"4px 6px",overflow:"hidden",cursor:"pointer",fontSize:10,display:"flex",flexDirection:"column",gap:2}}
                onMouseEnter={e=>e.currentTarget.style.background=isCM?"#F3F4F6":"#F9FAFB"} onMouseLeave={e=>e.currentTarget.style.background=isCM?"#FAFAFA":"#fff"}>
                <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",gap:4}}>
                  <span style={{fontSize:8.5,fontFamily:"monospace",color:"#9CA3AF",flexShrink:0}}>{c.startMin}</span>
                  <span style={{background:sg.c,color:"#fff",fontSize:8,fontWeight:700,padding:"0.5px 4px",borderRadius:2,flexShrink:0}}>{sg.lb}</span>
                </div>
                <div style={{fontSize:9,color:"#9CA3AF",fontWeight:500,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>📺 {c.progName}</div>
                <div style={{fontSize:11,fontWeight:600,color:"#111827",lineHeight:1.25,overflow:"hidden",textOverflow:"ellipsis",display:"-webkit-box",WebkitLineClamp:compact?1:2,WebkitBoxOrient:"vertical"}}>{c.title}</div>
                {!compact&&height>=60&&<div style={{fontSize:9,color:"#6B7280",lineHeight:1.3,overflow:"hidden",textOverflow:"ellipsis",display:"-webkit-box",WebkitLineClamp:Math.max(1,Math.floor((height-60)/12)),WebkitBoxOrient:"vertical"}}>{c.summary}</div>}
                <div style={{marginTop:"auto",display:"flex",gap:4,alignItems:"center",flexWrap:"wrap"}}>
                  {iV!=null&&<span style={{fontSize:9,fontFamily:"monospace",color:st.c,fontWeight:700}}>IN {fmt(iV)}</span>}
                  {oV!=null&&<span style={{fontSize:9,fontFamily:"monospace",color:st.c,fontWeight:700}}>OUT {fmt(oV)}</span>}
                  {df!=null&&<span style={{fontSize:9,fontFamily:"monospace",fontWeight:700,color:df>=0?"#16A34A":"#DC2626"}}>{df>=0?"+":""}{metric==="share"?df.toFixed(1):df.toFixed(2)}</span>}
                </div>
              </div>;
            })}
          </div>
        </div>;
      })}
    </div>
  </div>;
}

// ============= Search Page =============
// Search / Analysis で使う実データ対象日（視聴率の実データがある日）
const ALL_DATES=(()=>{const d=[];for(let i=1;i<=14;i++){d.push(`2026-04-${String(i).padStart(2,"0")}`);}d.push("2026-04-17");return d;})();
const ALL_SLOTS=["morning","evening"];

// 番組表・Dashboard 共通の日付範囲定数
const GUIDE_DATE_MIN="2025-06-25";
const GUIDE_DATE_MAX=(()=>{
  const t=new Date();
  const d=t.getDay();
  const back=d===0?6:d-1;
  t.setDate(t.getDate()-back);
  return t.toISOString().slice(0,10);
})();

// Dashboard 日付セレクタ用: 番組表と同じ範囲（GUIDE_DATE_MIN〜GUIDE_DATE_MAX）
const DASHBOARD_DATES=(()=>{
  const d=[];
  const cur=new Date(GUIDE_DATE_MIN);
  const end=new Date(GUIDE_DATE_MAX);
  while(cur<=end){d.push(cur.toISOString().slice(0,10));cur.setDate(cur.getDate()+1);}
  return d;
})();

// 視聴率遅延キャッシュ
// TODO: AWS移行時は genRatings → S3/DynamoDB APIへの差し替えポイント
const rCache={};
function getRatings(date,slot){
  const key=`${date}|${slot}`;
  if(!rCache[key])rCache[key]=genRatings(date,slot);
  return rCache[key];
}
// ALL_DATES分を初期ロード（Search/Analysisで使用）
(()=>{for(const d of ALL_DATES)for(const s of ALL_SLOTS)getRatings(d,s);})();

function buildCornerIndex(){
  const idx=[];
  for(const date of ALL_DATES){
    for(const slot of ALL_SLOTS){
      const tpl=slot==="morning"?getDailyMorn(date):getDailyEve(date);
      for(const stId of ST.map(s=>s.id)){
        const progs=tpl[stId]||[];
        for(const[progName,pStart,pEnd,corners] of progs){
          for(const cn of corners){
            const[title,cs,ce,segment,tags,summary]=cn;
            idx.push({date,slot,stId,progName,title,startMin:cs,endMin:ce,segment,tags,summary,id:`${date}|${slot}|${stId}|${cs}|${title}`});
          }
        }
      }
    }
  }
  return idx;
}

function computeCornerStats(corner,cache,metric){
  const key=`${corner.date}|${corner.slot}`;
  const rData=cache[key];
  if(!rData)return{iV:null,oV:null,avg:null,df:null};
  let src=rData;
  if(metric==="share"){
    src=rData.map(e=>{const t=ST.reduce((s,st)=>s+(e[st.id]||0),0);const o={time:e.time,minute:e.minute};ST.forEach(s=>{o[s.id]=t>0?(e[s.id]/t)*100:0;});return o;});
  }
  const sM=t2m(corner.startMin),eM=t2m(corner.endMin);
  const last=src[src.length-1].minute;
  const iE=src.find(d=>d.minute===sM);
  const oE=src.find(d=>d.minute===Math.min(eM,last));
  const slice=src.filter(d=>d.minute>=sM&&d.minute<Math.min(eM,last+1));
  const iV=iE?iE[corner.stId]:null;
  const oV=oE?oE[corner.stId]:null;
  const avg=slice.length>0?slice.reduce((s,d)=>s+d[corner.stId],0)/slice.length:null;
  const df=(iV!=null&&oV!=null)?oV-iV:null;
  return{iV,oV,avg,df};
}

